// -----------------------------------------------------------------------------
// The Optimized "Railgun" Scalar Heuristic (Order 4)
// -----------------------------------------------------------------------------
void swampwalker_railgun_scalar(const uint8_t* pbPattern, size_t cbPattern, size_t* outPosition, size_t* outLength) {
    size_t PRIMALlength = 0;
    size_t PRIMALposition = 1;
    
    // Equivalent to cbPattern - ((4)-1)
    size_t cbLimit = (cbPattern >= 4) ? (cbPattern - 3) : 0;

    for (size_t i = 1; i <= cbLimit; i++) {
        // Global Bailout: If the remaining text cannot possibly beat the best length, stop.
        if (cbPattern - i + 1 <= PRIMALlength) break;

        size_t FoundAtPosition = cbLimit + 1;
        
        // Horizon Clamping (Bailout = 128)
        size_t search_horizon = i + 128;
        if (FoundAtPosition > search_horizon) {
            FoundAtPosition = search_horizon;
        }

        // Search for Order-4 duplicates
        for (size_t cand = i; cand < FoundAtPosition; cand++) {
            uint32_t target = *(const uint32_t*)(pbPattern + cand - 1);
            
            for (size_t j = cand + 1; j < FoundAtPosition; j++) {
                if (*(const uint32_t*)(pbPattern + j - 1) == target) {
                    FoundAtPosition = j;
                    break; // Early exit on first collision
                }
            }
        }

        size_t PRIMALlengthCANDIDATE = FoundAtPosition - i + 3;
        
        // Use >= to match original logic (later positions overwrite earlier ties)
        if (PRIMALlengthCANDIDATE >= PRIMALlength) {
            PRIMALposition = i;
            PRIMALlength = PRIMALlengthCANDIDATE;
        }

        // Bail Out for 129[+]
        if (PRIMALlength > 128) break; 
    }

    *outPosition = PRIMALposition;
    *outLength = PRIMALlength;
}

