// ASCII 000 terminated buffer ]

void insert_char(char codepoint) {
    if (overwrite_mode) {
        if (cursor_pos < MAX_INPUT_LEN) {
            input_buffer[cursor_pos] = codepoint;
            // If we are at the end of the current length, expand it
            if (cursor_pos == input_len) {
                input_len++;
            }
            cursor_pos++;
        }
    } else {
        if (input_len < MAX_INPUT_LEN) {
            // Shift everything right, then insert
            memmove(&input_buffer[cursor_pos + 1], &input_buffer[cursor_pos], input_len - cursor_pos);
            input_buffer[cursor_pos++] = codepoint;
            input_len++;
        }
    }
}

