// Rasterizes a buffer of exact length (supports 0x00 as a valid character)
void draw_buffer(int x, int y, const char* buf, int zoomX, int zoomY, int len) {
    int cursor_x = x;
    for (int i = 0; i < len; i++) {
        unsigned char ch = buf[i];
        
        glBegin(GL_QUADS);
        for (int row = 0; row < 16; row++) {
            unsigned char row_data;
            if (WhichFont) {
            row_data = font_Mx437_CL_Stingray_8x16[ch][row];
            } else {
            row_data = fontTM[ch][row];
            }

            for (int col = 0; col < 8; col++) {
                if (row_data & (1 << (7 - col))) {
                    int px = cursor_x + (col * zoomX);
                    int py = y + ((15 - row) * zoomY); 
                    
                    glVertex2i(px, py);
                    glVertex2i(px + zoomX, py);
                    glVertex2i(px + zoomX, py + zoomY);
                    glVertex2i(px, py + zoomY);
                }
            }
        }
        glEnd();
        
        cursor_x += 10 * zoomX; // Move cursor for next char
    }
}

// 8x16
// Rasterizer (Removed hardcoded color so caller dictates text color)
void draw_string(int x, int y, const char* str, int zoomX, int zoomY) {
    int cursor_x = x;
    while (*str) {
        unsigned char ch = *str;
        
        glBegin(GL_QUADS);
        for (int row = 0; row < 16; row++) {
            unsigned char row_data;
            if (WhichFont) {
            row_data = font_Mx437_CL_Stingray_8x16[ch][row];
            } else {
            row_data = fontTM[ch][row];
            }
            for (int col = 0; col < 8; col++) {
                if (row_data & (1 << (7 - col))) {
                    int px = cursor_x + (col * zoomX);
                    int py = y + ((15 - row) * zoomY); 
                    
                    glVertex2i(px, py);
                    glVertex2i(px + zoomX, py);
                    glVertex2i(px + zoomX, py + zoomY);
                    glVertex2i(px, py + zoomY);
                }
            }
        }
        glEnd();
        
        cursor_x += 10 * zoomX; // 8px char + 2px spacing, scaled by X zoom
        str++;
    }
}

