// 16x32
void draw_string_16x32(int x, int y, const char* str, int zoomX, int zoomY) {
    int cursor_x = x;
    while (*str) {
        unsigned char ch = *str;
        
        glBegin(GL_QUADS);
            for (int row = 0; row < 32; row++) {
                // Combine two consecutive bytes to form a 16-bit row
                unsigned short R = (fontCORDATA32[(unsigned char)ch][row * 2] << 8) | fontCORDATA32[(unsigned char)ch][row * 2 + 1];
                for (int col = 0; col < 16; col++) {
                    if (R & (1 << (15 - col))) { // Check each bit in the 16-bit row

                    int px = cursor_x + (col * zoomX);
                    int py = y + ((15 - row) * zoomY); 
                    
                    glVertex2i(px, py);
                    glVertex2i(px + zoomX, py);
                    glVertex2i(px + zoomX, py + zoomY);
                    glVertex2i(px, py + zoomY);

                    }
                }
            }
        glEnd();
        
        cursor_x += (16+2) * zoomX; // 8px char + 2px spacing, scaled by X zoom
        str++;
    }
}

// Bypasses null-termination to draw the raw glyph from your font array
void draw_raw_char(int x, int y, unsigned char c, int zoomX, int zoomY) {
    char single_char_str[2];
    single_char_str[0] = c;
    single_char_str[1] = '\0'; 
    
    // If your draw_string breaks on single_char_str[0] == 0, 
    // you must call your font rendering loop directly here instead:
    // e.g., render_bitmap_glyph(x, y, font[c], zoomX, zoomY);
    
    // Assuming your draw_string can handle length 1 if passed directly:
    draw_string(x, y, single_char_str, zoomX, zoomY);
}

void render_ascii_table(int win_width) {
    // Darker pastel background for the secondary window
    glClearColor(0.12f, 0.12f, 0.15f, 1.0f);
    glClear(GL_COLOR_BUFFER_BIT);

    // Grid spacing math
    int start_x = 20;
    int start_y = 24;
    int col_width = (win_width - 40) / 8; // Divide available width by 8 columns
    int row_height = (FONT_HEIGHT + 3) * zoomVARy;       // Adjust based on your font height

    char num_buf[8];

    for (int i = 0; i < 256; i++) {
        int col = i / 16;
        int row = i % 16;
        
        int x = start_x + (col * col_width);
        int y = start_y + (row * row_height);

        // 1. Draw the prefix number (e.g., "001 ")
        sprintf(num_buf, "%03d  ", i);
        glColor4f(0.5f, 0.5f, 0.6f, 0.9f); // Dim grey for the numbers
        draw_string(x, y, num_buf, zoomVARx, zoomVARy);

        // 2. Draw the actual raw glyph next to it
        // Offset X by the width of "000 " (4 characters * char_width)
        int glyph_offset_x = x + (5 * 8 * zoomVARx); // Assuming 8px base font width
        glColor4f(0.9f, 0.7f, 0.5f, 0.9f); // Pastel purple for the glyphs
        
        // Special manual override for 000 if your draw_string absolutely fails on it
        if (i == 0) {
            // Call your internal geometry draw loop directly for font[0] here
            // draw_raw_char(glyph_offset_x, y, 0, zoomVARx, zoomVARy);
            draw_ASCII000(glyph_offset_x, y, zoomVARx, zoomVARy);
        } else {
            draw_raw_char(glyph_offset_x, y, (unsigned char)i, zoomVARx, zoomVARy);
        }
    }
}

