// Renders the interactive virtual keyboard (5 rows)
void draw_virtual_keyboard(int mx, int my) {
    for (int row = 0; row < VKy; row++) {
        for (int col = 0; col < VKx; col++) {
            int x = XpadForBorder + col * (key_w + gap);
            int y = Positioned_at_bottom - (row * (key_h + gap));


            if ((row==2 || row==3) && col<26) { // ASCII 000 is special case
            // Draw Box
            glColor4f(0.3f, 0.3f, 0.35f, 0.9f);
            glBegin(GL_QUADS);
                glVertex2i(x, y);
                glVertex2i(x + key_w, y);
                glVertex2i(x + key_w, y + key_h);
                glVertex2i(x, y + key_h);
            glEnd();
            } else {
            // Draw Box
            glColor4f(0.2f, 0.2f, 0.25f, 0.9f);
            glBegin(GL_QUADS);
                glVertex2i(x, y);
                glVertex2i(x + key_w, y);
                glVertex2i(x + key_w, y + key_h);
                glVertex2i(x, y + key_h);
            glEnd();
            }
            // Draw Text
            glColor4f(1.0f, 1.0f, 1.0f, 0.9f);

            // --- DETERMINING KEY FACE COLOR ---
            if (row == clicked_row && col == clicked_col && (glfwGetTime() - click_timestamp < 0.15)) {
                // 150ms Click Feedback Color (A striking vibrant pastel pink/red accent)
                glColor4f(0.6f, 0.6f, 0.1f, 0.9f); // Yellowish

                // Draw Box
                glBegin(GL_QUADS);
                    glVertex2i(x, y);
                    glVertex2i(x + key_w, y);
                    glVertex2i(x + key_w, y + key_h);
                    glVertex2i(x, y + key_h);
                glEnd();
                glColor4f(0.1f, 0.1f, 0.1f, 0.9f);

            }
            else if (mx >= x && mx <= x + key_w && my >= y && my <= y + key_h) {
                // Normal Hover Highlight Color
                glColor4f(0.5f, 0.5f, 0.9f, 0.9f); 
            } 
            else {
                // Default Keyboard Key Color
                glColor4f(1.0f, 1.0f, 1.0f, 0.9f);
            }

            draw_string(x + (key_w/4), y + (key_h/4), key_layout[row][col], zoomVARx, zoomVARy);

            if (row==6 && col==26) { // ASCII 000 is special case
                draw_ASCII000(x + (key_w/4), y + (key_h/4), zoomVARx, zoomVARy);
            }

        }
    }
}

// The undisputed king of "I just want to write a 20-line C parser for an image with transparency" is the **Uncompressed 32-bit TGA (Truevision Targa)** format.
// TGA files have a dead-simple, fixed 18-byte header, natively support an 8-bit alpha channel (RGBA), and don't have the annoying 4-byte row padding that BMPs have.
// Loads an uncompressed 32-bit TGA (RGBA) and uploads it to OpenGL
GLuint load_tga_texture(const char *filename, int *width, int *height) {
    FILE *f = fopen(filename, "rb");
    if (!f) {
        // Silently fail if no mascot is found, keeping it optional
        return 0; 
    }

    unsigned char header[18];
    if (fread(header, 1, 18, f) != 18) {
        fclose(f);
        return 0;
    }

    // Image type 2 is Uncompressed True-Color
    if (header[2] != 2) {
        printf("Mascot error: TGA must be uncompressed.\n");
        fclose(f);
        return 0;
    }

    // Calculate dimensions from header bytes
    *width = header[12] + (header[13] << 8);
    *height = header[14] + (header[15] << 8);
    int bpp = header[16];

    if (bpp != 32) {
        printf("Mascot error: TGA must be exported as 32-bit (RGBA) to support transparency.\n");
        fclose(f);
        return 0;
    }

    int image_size = (*width) * (*height) * 4; // 4 bytes per pixel (RGBA)
    unsigned char *data = (unsigned char *)malloc(image_size);

    // Skip the Image ID field if the exporter included one
    if (header[0] > 0) fseek(f, header[0], SEEK_CUR);

    fread(data, 1, image_size, f);
    fclose(f);

    // TGA files store pixels in Blue-Green-Red-Alpha order.
    // OpenGL expects Red-Green-Blue-Alpha. We swap the R and B bytes.
    for (int i = 0; i < image_size; i += 4) {
        unsigned char temp = data[i];     // Blue
        data[i] = data[i + 2];            // Red
        data[i + 2] = temp;               // Blue
    }

    GLuint tex;
    glGenTextures(1, &tex);
    glBindTexture(GL_TEXTURE_2D, tex);
    
    // Pixel-perfect scaling
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
    
    glPixelStorei(GL_UNPACK_ALIGNMENT, 1);
    
    // Notice we use GL_RGBA now instead of GL_RGB!
    glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, *width, *height, 0, GL_RGBA, GL_UNSIGNED_BYTE, data);

    free(data);
    return tex;
}
