// This is the ultimate finishing touch. A living, breathing animated mascot floating over a terminal UI is peak hacker aesthetic!
// To do this right, we will absolutely honor your "one `malloc()`" idea because reading 124 files from disk into a single contiguous block of system RAM is incredibly fast for I/O.
// However, we are going to add one crucial OpenGL step: once that giant `malloc` block is filled, we will instantly slice it up and upload it
// to 124 individual **OpenGL Texture IDs** in your Video RAM (VRAM), and then `free()` the system RAM.
// If we didn't do this, your CPU would have to push megabytes of pixel data to the graphics card every single frame, which would completely destroy your butter-smooth pixel scrolling.

// That's it! By reading all files into a giant `malloc` buffer, you avoid hard-drive bottlenecks, and by uploading them as separate `GLuint` textures,
// OpenGL can swap between them at a blisteringly fast 60+ FPS without breaking a sweat.
// Adjust `mascot_fps` at the top of the file to speed up or slow down the robot's movement.

// Loads an entire TGA sequence into ONE malloc, uploads to VRAM, and frees the RAM
void load_tga_animation(const char *name_template, int num_frames, GLuint *tex_array, int *width, int *height) {
    char filename[256];
    
    // 1. Peek at the first frame just to get the width and height
    sprintf(filename, name_template, 1);
    FILE *f = fopen(filename, "rb");
    if (!f) {
        printf("Could not find first frame: %s\n", filename);
        return;
    }
    
    unsigned char header[18];
    fread(header, 1, 18, f);
    *width = header[12] + (header[13] << 8);
    *height = header[14] + (header[15] << 8);
    fclose(f);

    // 2. THE ONE MALLOC: Allocate exact RAM for all frames combined
    size_t single_frame_size = (*width) * (*height) * 4; // 32-bit RGBA
    unsigned char *giant_buffer = (unsigned char *)malloc(single_frame_size * num_frames);
    if (!giant_buffer) {
        printf("Memory allocation failed for mascot animation.\n");
        return;
    }

    // 3. Blast all files into the contiguous memory block
    for (int i = 0; i < num_frames; i++) {
        sprintf(filename, name_template, i + 1); // Generates 001, 002, etc.
        f = fopen(filename, "rb");
        if (f) {
            fread(header, 1, 18, f);
            if (header[0] > 0) fseek(f, header[0], SEEK_CUR); // Skip Image ID if present
            
            // Read directly into the correct offset of the giant buffer
            fread(giant_buffer + (i * single_frame_size), 1, single_frame_size, f);
            fclose(f);

            // BGR to RGB Swap for this specific frame
            unsigned char *frame_data = giant_buffer + (i * single_frame_size);
            for (size_t j = 0; j < single_frame_size; j += 4) {
                unsigned char temp = frame_data[j];     // Blue
                frame_data[j] = frame_data[j + 2];      // Red
                frame_data[j + 2] = temp;               // Blue
            }
        }
    }

    // 4. Generate 124 texture IDs and upload the slices to VRAM
    glGenTextures(num_frames, tex_array);
    for (int i = 0; i < num_frames; i++) {
        glBindTexture(GL_TEXTURE_2D, tex_array[i]);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
        glPixelStorei(GL_UNPACK_ALIGNMENT, 1);
        
        glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, *width, *height, 0, GL_RGBA, GL_UNSIGNED_BYTE, giant_buffer + (i * single_frame_size));
    }

    // 5. Free the system RAM! (The GPU now owns the animation)
    free(giant_buffer);
    printf("Successfully loaded %d mascot frames to VRAM.\n", num_frames);
}

// Dynamic array structure for thread-local hit accumulation
typedef struct {
    int64_t *offsets;
    size_t count;
    size_t capacity;
} HitList;

// Helper to push hits to a thread's private list
static inline void add_hit(HitList *list, int64_t offset) {
    if (list->count >= list->capacity) {
        list->capacity = (list->capacity == 0) ? 1024 : list->capacity * 2;
        list->offsets = (int64_t *)realloc(list->offsets, list->capacity * sizeof(int64_t));
    }
    list->offsets[list->count++] = offset;
}

// Main multi-threaded batch search function (LF Capped)
int64_t ePEN_extract_all_hits_lf_bound(const char *file_buf, size_t file_size, 
                                       const char *pattern, int max_edit_distance) {
    if (!file_buf || file_size == 0 || !pattern) return 0;
    
    size_t pattern_len = strlen(pattern);
    if (pattern_len == 0) return 0;

    int max_threads = omp_get_max_threads();
    if (max_threads > 256) max_threads = 256;
    omp_set_num_threads(max_threads);

    size_t raw_chunk_size = file_size / max_threads;
    if (raw_chunk_size == 0) {
        raw_chunk_size = file_size;
        max_threads = 1;
    }
    
    // Allocate private hit lists for each thread
    HitList *thread_hits = (HitList *)calloc(max_threads, sizeof(HitList));
    if (!thread_hits) return -1;

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t raw_start = tid * raw_chunk_size;
        size_t raw_end = (tid == max_threads - 1) ? file_size : (tid + 1) * raw_chunk_size;
        
        // --- SNAP TO LF BOUNDARIES ---
        size_t adj_start = raw_start;
        if (tid > 0) {
            while (adj_start < file_size && file_buf[adj_start - 1] != '\n') {
                adj_start++;
            }
        }

        size_t adj_end = raw_end;
        if (tid != max_threads - 1) {
            while (adj_end < file_size && file_buf[adj_end - 1] != '\n') {
                adj_end++;
            }
        }

        // Only proceed if this thread actually has a valid chunk
        if (adj_start < adj_end) {
            size_t M = pattern_len;
            int K = max_edit_distance;
            
            // Pre-allocate Levenshtein buffers once per thread (if doing fuzzy)
            int *prev_col = NULL;
            int *curr_col = NULL;
            if (K > 0) {
                prev_col = (int *)malloc((M + 1) * sizeof(int));
                curr_col = (int *)malloc((M + 1) * sizeof(int));
            }

            size_t current_idx = adj_start;
            
            // --- LINE-BY-LINE PROCESSING WITHIN THREAD CHUNK ---
            while (current_idx < adj_end) {
                // Find the LF for this specific line
                size_t line_end = current_idx;
                while (line_end < file_size && file_buf[line_end] != '\n') {
                    line_end++;
                }
                
                size_t line_len = line_end - current_idx;

                if (line_len >= M || K > 0) {
                    // CASE #1: Exact Search
                    if (K == 0) {
                        const char *search_ptr = file_buf + current_idx;
                        size_t remaining = line_len;
                        const char *match;

                        while ((match = (const char *)memmem(search_ptr, remaining, pattern, M)) != NULL) {
                            size_t offset = match - file_buf;
                            add_hit(&thread_hits[tid], (int64_t)offset);
                            search_ptr = match + 1; // Advance by 1 to catch overlaps (e.g., "ana" in "banana")
                            remaining = (file_buf + line_end) - search_ptr;
                            if (remaining <= 0) break;
                        }
                    } 
                    // CASE #2: Fuzzy Levenshtein Search
                    else if (prev_col && curr_col) {
                        for (size_t idx = 0; idx <= M; idx++) prev_col[idx] = (int)idx;
                        
                        const char *line_buf = file_buf + current_idx;
                        int64_t last_recorded = -1;

                        // Search strictly within this line
                        for (size_t j = 0; j < line_len; j++) {
                            curr_col[0] = 0; 
                            char text_char = line_buf[j];

                            for (size_t k_idx = 1; k_idx <= M; k_idx++) {
                                int cost = (pattern[k_idx - 1] == text_char) ? 0 : 1;
                                int del = prev_col[k_idx] + 1;
                                int ins = curr_col[k_idx - 1] + 1;
                                int sub = prev_col[k_idx - 1] + cost;

                                int min_val = del;
                                if (ins < min_val) min_val = ins;
                                if (sub < min_val) min_val = sub;
                                curr_col[k_idx] = min_val;
                            }

                            if (curr_col[M] <= K) {
                                size_t absolute_end_idx = current_idx + j;
                                size_t est_start_idx = (absolute_end_idx >= M) ? (absolute_end_idx - M + 1) : current_idx;
                                
                                // Clamp to start of the line just in case
                                if (est_start_idx < current_idx) est_start_idx = current_idx;

                                // Prevent clustering duplicates
                                if (last_recorded == -1 || (est_start_idx > (size_t)last_recorded)) {
                                    add_hit(&thread_hits[tid], (int64_t)est_start_idx);
                                    last_recorded = est_start_idx;
                                }
                            }

                            int *tmp = prev_col; prev_col = curr_col; curr_col = tmp;
                        }
                    }
                }
                
                // Move pointer to the start of the next line
                current_idx = line_end + 1;
            }

            if (prev_col) free(prev_col);
            if (curr_col) free(curr_col);
        }
    }

    // --- SEQUENTIAL FILE WRITING ---
    FILE *out_file = fopen("fuzzy.hits", "w");
    int64_t total_hits = 0;

    if (out_file) {
        for (int i = 0; i < max_threads; i++) {
            for (size_t j = 0; j < thread_hits[i].count; j++) {
                fprintf(out_file, "%lld\n", (long long)thread_hits[i].offsets[j]);
                total_hits++;
            }
        }
        fclose(out_file);
    }

    // Clean up memory
    for (int i = 0; i < max_threads; i++) {
        if (thread_hits[i].offsets) {
            free(thread_hits[i].offsets);
        }
    }
    free(thread_hits);

    return total_hits;
}

/*
How the Ecosystem Fits Together
By separating the search from the expansion, you've created a highly modular, professional-grade backend:

Phase 1 (The OpenMP Engine): Only cares about raw byte arrays, mathematics, and Levenshtein matrices. It runs at the absolute physical limit of your CPU, dumping integers to disk.

Phase 2 (The Expander): ePEN_expand_hits_to_lines acts as the formatter. It doesn't need to know anything about wildcards, edit distances, or threads.

Memory Safety: The expander uses fwrite directly on pointer arithmetic (file_buf + line_start). It does not allocate intermediate strings or call malloc to hold the line, meaning it uses zero extra RAM, regardless of whether a line is 10 characters or 10 megabytes long.

Chronological Output: Because fuzzy.hits was dumped sequentially by the previous engine, the offsets are guaranteed to be moving downward through the file. This allows the last_line_end deduplication logic to work flawlessly.
*/

/*
This is the perfect final piece to complete the architecture. You have a blazingly fast indexer that generates the fuzzy.hits file, and now you need a resolver to expand those raw byte offsets back into human-readable text.

To make this truly robust for a text editor or grep-like tool, this expansion function needs to handle one critical edge case: Deduplication. Because our previous OpenMP engine finds every hit (even multiple hits on the same line), blindly expanding every offset would cause the same physical line to be printed multiple times.

The function below reads the offsets sequentially, expands them by walking backwards and forwards to the nearest LF (\n), and automatically skips offsets that belong to a line it has already extracted.
*/

// Reads the hits file and extracts the full LF-bounded lines to an output file
int64_t ePEN_expand_hits_to_lines(const char *file_buf, size_t file_size, 
                                  const char *hits_filename, const char *out_filename) {
    if (!file_buf || file_size == 0 || !hits_filename || !out_filename) return -1;

    FILE *hits_file = fopen(hits_filename, "r");
    if (!hits_file) {
        printf("Error: Could not open %s for reading.\n", hits_filename);
        return -1;
    }

    FILE *out_file = fopen(out_filename, "w");
    if (!out_file) {
        printf("Error: Could not open %s for writing.\n", out_filename);
        fclose(hits_file);
        return -1;
    }

    int64_t offset;
    int64_t last_line_end = -1;
    int64_t lines_written = 0;

    // Read offsets sequentially from the file
    while (fscanf(hits_file, "%lld", (long long *)&offset) == 1) {
        // Safety bounds check
        if (offset < 0 || (size_t)offset >= file_size) continue;

        // --- DEDUPLICATION CHECK ---
        // If this offset falls before the end of the last line we printed, 
        // it means this is a secondary hit on the same line. Skip it.
        if (last_line_end != -1 && offset <= last_line_end) {
            continue;
        }

        // --- 1. FIND LEFT BOUNDARY (Start of Line) ---
        int64_t line_start = offset;
        while (line_start > 0 && file_buf[line_start - 1] != '\n') {
            line_start--;
        }

        // --- 2. FIND RIGHT BOUNDARY (End of Line / CAP) ---
        int64_t line_end = offset;
        while ((size_t)line_end < file_size && file_buf[line_end] != '\n') {
            line_end++;
        }

        // Calculate the exact chunk size to write
        size_t write_len = line_end - line_start;
        
        // If we found an actual LF (not just EOF), include it in the output
        if ((size_t)line_end < file_size && file_buf[line_end] == '\n') {
            write_len++; // Expand length to catch the '\n'
            last_line_end = line_end; 
        } else {
            last_line_end = line_end - 1; // Reached EOF without LF
        }

        // --- 3. HIGH-SPEED EXTRACTION ---
        // Blast the exact physical line directly from the memory buffer to the file
        fwrite(file_buf + line_start, 1, write_len, out_file);
        lines_written++;
    }

    fclose(hits_file);
    fclose(out_file);

    return lines_written; // Returns the number of unique physical lines extracted
}

// The Complete Wildcard Hit Extractor [[[

// --- HELPERS ---
static inline bool is_alpha_char(char c) {
    return (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z');
}

// --- CORE RECURSIVE ENGINE (LF-Bounded) ---
static bool is_wildcard_match(const char *text, size_t t_len, const char *pat, size_t p_len, int depth) {
    if (depth > 256) return false;
    size_t t = 0, p = 0;
    while (p < p_len) {
        char wc = pat[p];
        if (wc == '*' || wc == '.' || wc == '%') {
            if (p + 1 == p_len) return true;
            size_t limit = (t_len - t > 2048) ? 2048 : (t_len - t);
            size_t max_skip = 0;
            if (wc == '*') max_skip = limit;
            else if (wc == '.') { while (max_skip < limit && is_alpha_char(text[t + max_skip])) max_skip++; }
            else if (wc == '%') { while (max_skip < limit && !is_alpha_char(text[t + max_skip])) max_skip++; }

            for (size_t skip = 0; skip <= max_skip; skip++) {
                if (is_wildcard_match(text + t + skip, t_len - t - skip, pat + p + 1, p_len - p - 1, depth + 1)) return true;
            }
            return false;
        }
        else if (wc == '@' || wc == '^' || wc == '|') {
            if (is_wildcard_match(text + t, t_len - t, pat + p + 1, p_len - p - 1, depth + 1)) return true;
            if (t < t_len) {
                bool valid = (wc == '@') || (wc == '^' && is_alpha_char(text[t])) || (wc == '|' && !is_alpha_char(text[t]));
                if (valid && is_wildcard_match(text + t + 1, t_len - t - 1, pat + p + 1, p_len - p - 1, depth + 1)) return true;
            }
            return false;
        }
        else if (wc == '#' || wc == '$' || wc == '~') {
            if (t >= t_len) return false;
            bool valid = (wc == '#') || (wc == '$' && is_alpha_char(text[t])) || (wc == '~' && !is_alpha_char(text[t]));
            if (!valid) return false;
            t++; p++;
        }
        else {
            if (t >= t_len || text[t] != wc) return false;
            t++; p++;
        }
    }
    return true;
}

// --- MAIN PARALLEL EXTRACTOR ---
int64_t ePEN_extract_wildcard_hits(const char *file_buf, size_t file_size, const char *pattern) {
    size_t pattern_len = strlen(pattern);
    int max_threads = omp_get_max_threads();
    if (max_threads > 256) max_threads = 256;
    omp_set_num_threads(max_threads);

    HitList *thread_hits = (HitList *)calloc(max_threads, sizeof(HitList));
    size_t raw_chunk_size = file_size / max_threads;

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t raw_start = tid * raw_chunk_size;
        size_t raw_end = (tid == max_threads - 1) ? file_size : (tid + 1) * raw_chunk_size;
        
        // SNAP TO LF BOUNDARIES
        size_t adj_start = raw_start;
        if (tid > 0) { while (adj_start < file_size && file_buf[adj_start - 1] != '\n') adj_start++; }
        size_t adj_end = raw_end;
        if (tid != max_threads - 1) { while (adj_end < file_size && file_buf[adj_end - 1] != '\n') adj_end++; }

        size_t current_idx = adj_start;
        while (current_idx < adj_end) {
            size_t line_end = current_idx;
            while (line_end < file_size && file_buf[line_end] != '\n') line_end++;
            
            for (size_t start = current_idx; start < line_end; start++) {
                if (is_wildcard_match(file_buf + start, line_end - start, pattern, pattern_len, 0)) {
                    add_hit(&thread_hits[tid], (int64_t)start);
                }
            }
            current_idx = line_end + 1;
        }
    }

    // SEQUENTIAL DUMP
    FILE *out_file = fopen("wildcard.hits", "w");
    int64_t total_hits = 0;
    if (out_file) {
        for (int i = 0; i < max_threads; i++) {
            for (size_t j = 0; j < thread_hits[i].count; j++) {
                fprintf(out_file, "%lld\n", (long long)thread_hits[i].offsets[j]);
                total_hits++;
            }
        }
        fclose(out_file);
    }

    for (int i = 0; i < max_threads; i++) free(thread_hits[i].offsets);
    free(thread_hits);
    return total_hits;
}

